0b-commonjs-vs-es-modules.code_example:
import { createServer } from 'http';
const server = createServer((req, res) => {
  res.writeHead(200);
  res.end('Hello World!
');
});
server.listen(3000, () => {
  console.log('Server running on port 3000');
});

0b-commonjs-vs-es-modules.golden_snippet:
import { createServer } from 'http';
const server = createServer((req, res) => {
  const currentTime = new Date().toLocaleTimeString();
  res.writeHead(200);
  res.end(`Hello World! (Current Time: ${currentTime})
`);
});
server.listen(3000, () => {
  console.log('Server running on port 3000');
});

